def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        score = 0.0
        multiplier = 1.0 + 0.5 * np.sin(item / (cap + 1))
        penalty = 0.0
        adjustment = 1.0
        ratio = item / cap
        for j in range(1, 15):
            factor = np.cos(ratio * j * 1.5) + np.log1p(j + cap % (j+2))
            if j % 4 == 0:
                multiplier *= (1 + 0.03 * j)
            elif j % 6 == 0:
                multiplier *= (0.9 - 0.02 * j/6)
            if ratio < 0.1 * j:
                score += (j**3) / (1 + np.exp(-ratio * j)) * multiplier * factor
            else:
                score += (np.sqrt(j*j*j) + ratio**2.5) * multiplier / (j + 1) * factor
            if (cap + j*j*2) % 5 == 0:
                score *= 1.07
            elif (cap*j*j) % 8 == 4:
                score *= 0.93
            if j == 7:
                for k in range(1, 8):
                    diff = cap - item * (k**3)
                    if diff > 0:
                        if diff % (k + 4) == 0:
                            penalty += np.cbrt(diff) / (k + 5)
                        else:
                            penalty -= np.log1p(abs(diff)) / (k + 3)
                    else:
                        penalty -= abs(diff) ** 1.5 / (k + 6)
            if ratio > 0.9 and j % 3 == 0:
                adjustment *= 1.12 + 0.015 * j
            elif ratio < 0.15 and j % 5 == 0:
                adjustment *= 0.88 - 0.02 * j/5
            if j % 5 == 1 and cap % (j + 3) == 0:
                penalty += np.cos(j * ratio) * 0.7
            elif j % 2 == 0 and cap % (j + 1) == 1:
                penalty -= np.sin(j * ratio * 1.3) * 0.6
            if j % 7 == 0:
                for m in range(1, 4):
                    cycle_val = (cap + m*j**2) % (m + j)
                    if cycle_val == 0:
                        penalty += np.tanh(m * ratio) / (m + j)
                    else:
                        penalty -= np.abs(np.sin(cycle_val)) / (m + j + 1)
        score += penalty * 0.85
        score *= adjustment
        if score <= 0:
            priorities[i] = -score * (np.log1p(cap + item) + np.sqrt(cap) + np.exp(-ratio))
        else:
            if cap > item * 6:
                priorities[i] = -score / (np.sqrt(cap) + 2) * (1 + 1.2*ratio)
            else:
                priorities[i] = -score / (cap + 5) * np.exp(-ratio**3)
        if ratio > 0.9:
            priorities[i] *= 1.2
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.97
        elif cap % 5 == 2:
            priorities[i] *= 1.03
        if i % 2 == 0:
            priorities[i] *= 1.01
        else:
            priorities[i] *= 0.99
    return priorities
